const failRunningDeploymentsForRecovery = `-- name: FailRunningDeploymentsForRecovery :many
WITH failed_deployments AS (
    UPDATE deployments
    SET status = 'failed',
        finished_at = now()
    WHERE status = 'running'
    RETURNING id, application_id, server_id, trigger, strategy, status, commit_sha, actor, started_at, finished_at, created_at, image_ref, image_digest, source_repository_url, source_branch, commit_message, configuration_snapshot
),
failed_applications AS (
    UPDATE applications
    SET status = 'failed',
        updated_at = now()
    WHERE id IN (SELECT application_id FROM failed_deployments)
    RETURNING id
)
SELECT failed_deployments.id,
       failed_deployments.application_id,
       failed_deployments.server_id,
       failed_deployments.trigger,
       failed_deployments.strategy,
       failed_deployments.status,
       failed_deployments.commit_sha,
       failed_deployments.image_ref,
       failed_deployments.image_digest,
       failed_deployments.source_repository_url,
       failed_deployments.source_branch,
       failed_deployments.commit_message,
       failed_deployments.configuration_snapshot,
       failed_deployments.actor,
       failed_deployments.started_at,
       failed_deployments.finished_at,
       failed_deployments.created_at
FROM failed_deployments
`

type FailRunningDeploymentsForRecoveryRow struct {
	ID                    pgtype.UUID        `json:"id"`
	ApplicationID         pgtype.UUID        `json:"application_id"`
	ServerID              pgtype.UUID        `json:"server_id"`
	Trigger               string             `json:"trigger"`
	Strategy              string             `json:"strategy"`
	Status                string             `json:"status"`
	CommitSha             pgtype.Text        `json:"commit_sha"`
	ImageRef              pgtype.Text        `json:"image_ref"`
	ImageDigest           pgtype.Text        `json:"image_digest"`
	SourceRepositoryUrl   pgtype.Text        `json:"source_repository_url"`
	SourceBranch          pgtype.Text        `json:"source_branch"`
	CommitMessage         pgtype.Text        `json:"commit_message"`
	ConfigurationSnapshot []byte             `json:"configuration_snapshot"`
	Actor                 pgtype.Text        `json:"actor"`
	StartedAt             pgtype.Timestamptz `json:"started_at"`
	FinishedAt            pgtype.Timestamptz `json:"finished_at"`
	CreatedAt             pgtype.Timestamptz `json:"created_at"`
}

func (q *Queries) FailRunningDeploymentsForRecovery(ctx context.Context) ([]FailRunningDeploymentsForRecoveryRow, error) {
	rows, err := q.db.Query(ctx, failRunningDeploymentsForRecovery)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []FailRunningDeploymentsForRecoveryRow{}
	for rows.Next() {
		var i FailRunningDeploymentsForRecoveryRow
		if err := rows.Scan(
			&i.ID,
			&i.ApplicationID,
			&i.ServerID,
			&i.Trigger,
			&i.Strategy,
			&i.Status,
			&i.CommitSha,
			&i.ImageRef,
			&i.ImageDigest,
			&i.SourceRepositoryUrl,
			&i.SourceBranch,
			&i.CommitMessage,
			&i.ConfigurationSnapshot,
			&i.Actor,
			&i.StartedAt,
			&i.FinishedAt,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

